INSERT INTO course_details (slug, lang, full_description, teacher_name, teacher_role, teacher_photo) VALUES
('english', 'Английский', 'На занятиях английским мы создаём для ребёнка среду, в которой хочется говорить. Дошкольники знакомятся с языком через песни, пальчиковые игры и простые диалоги с игрушками. Школьники разбирают темы через квесты, ролевые игры и просмотр коротких видео с носителями языка. Группы небольшие — до 6 человек, поэтому каждый ребёнок успевает высказаться и получить внимание преподавателя. За 8 занятий дети осваивают активный словарный запас по теме блока и учатся строить простые фразы без страха ошибиться.', 'Казакова Ксения Фёдоровна', 'Преподаватель английского и китайского языков', 'https://cdn.poehali.dev/projects/916f0912-2e1a-441b-ba48-3e1b39731153/bucket/4fc5576b-3629-4a6b-aaae-c60e197389cd.jpg'),
('chinese', 'Китайский', 'Китайский в нашей студии начинается не с иероглифов, а с любопытства. Мы показываем детям, что иероглиф — это маленькая картинка, а не абстрактный значок, поэтому дошкольники и школьники быстро включаются в процесс. На занятиях звучит музыка для отработки тонов, разбираются простые диалоги и элементы культуры Китая — праздники, сказки, традиции. К концу блока из 8 занятий ребёнок уверенно пишет базовые иероглифы и произносит короткие фразы с правильной интонацией.', 'Казакова Ксения Фёдоровна', 'Преподаватель английского и китайского языков', 'https://cdn.poehali.dev/projects/916f0912-2e1a-441b-ba48-3e1b39731153/bucket/4fc5576b-3629-4a6b-aaae-c60e197389cd.jpg'),
('mini-sad', 'Мини-сад', 'Мини-сад — это утренние субботние занятия для малышей 2–6 лет, пока родители заняты своими делами. Дети играют, лепят, рисуют и знакомятся с первыми английскими словами через сказки и подвижные игры. Формат мягкий и без давления: главная задача — чтобы ребёнку было интересно и комфортно в новой для него обстановке. Абонемент включает 4 посещения по 3 часа с лёгким перекусом.', 'Казакова Ксения Фёдоровна', 'Преподаватель английского и китайского языков', 'https://cdn.poehali.dev/projects/916f0912-2e1a-441b-ba48-3e1b39731153/bucket/4fc5576b-3629-4a6b-aaae-c60e197389cd.jpg'),
('teatr', 'Театральные постановки', 'Занятия по актёрскому мастерству на английском снимают главный барьер в изучении языка — страх ошибиться. Ребёнок говорит не от своего имени, а от лица персонажа, поэтому раскрепощается гораздо быстрее. В программе — разминки, импровизации, разбор ролей и постановка небольшого спектакля, который дети показывают родителям в конце блока. Идеально подходит стеснительным детям и тем, кто уже неплохо знает язык, но боится говорить вслух.', 'Казакова Ксения Фёдоровна', 'Преподаватель английского и китайского языков', 'https://cdn.poehali.dev/projects/916f0912-2e1a-441b-ba48-3e1b39731153/bucket/4fc5576b-3629-4a6b-aaae-c60e197389cd.jpg'),
('vyhodnoy', 'Группа выходного дня', 'Насыщенная суббота для школьников 1–4 класса: за одно занятие дети успевают позаниматься английским через игру, поучаствовать в мини-постановке и просто хорошо провести время в компании сверстников. Формат подходит семьям, у которых будни расписаны по минутам, а суббота — единственное окно для развивающих занятий.', 'Казакова Ксения Фёдоровна', 'Преподаватель английского и китайского языков', 'https://cdn.poehali.dev/projects/916f0912-2e1a-441b-ba48-3e1b39731153/bucket/4fc5576b-3629-4a6b-aaae-c60e197389cd.jpg');
